// Get static data (persisted across executions)
const staticData = $getWorkflowStaticData('global');
const lastNotifiedAt = staticData.lastNotifiedAt || '2026-01-01T00:00:00.000Z';

const invoicesData = $input.first().json;
const invoices = invoicesData.invoices || invoicesData.data || [];

if (!Array.isArray(invoices) || invoices.length === 0) {
  return [];
}

// Filter only invoices created after last notification
const newInvoices = invoices.filter(inv => {
  const createdAt = new Date(inv.createdAt || inv.importedAt || '2000-01-01');
  return createdAt > new Date(lastNotifiedAt);
});

if (newInvoices.length === 0) {
  return [];
}

// Update last notified timestamp to the most recent invoice
const mostRecent = newInvoices.reduce((latest, inv) => {
  const d = new Date(inv.createdAt || inv.importedAt || '2000-01-01');
  return d > latest ? d : latest;
}, new Date(lastNotifiedAt));

staticData.lastNotifiedAt = mostRecent.toISOString();

// Return each new invoice as separate item
return newInvoices.map(inv => ({
  json: {
    id: inv.id,
    number: inv.number,
    series: inv.series || '1',
    senderName: inv.senderName || inv.issuerName || 'Não identificado',
    senderCnpj: inv.senderCnpj || '',
    totalValue: inv.totalValue,
    issueDate: inv.issueDate,
    accessKey: inv.accessKey,
    createdAt: inv.createdAt
  }
}));

const inv = $('Filtrar Novas NF-e').item.json;
const pdfItem = $input.first();

// After adding "Baixar XML Original", binary has both `data` (PDF) and `xml` (XML).
// Reference the PDF explicitly to avoid Object.keys() ordering issues.
const binaryData = pdfItem.binary && pdfItem.binary.data;
if (!binaryData) {
  throw new Error('PDF binary missing (expected binary.data from Baixar DANFE PDF)');
}
const base64 = binaryData.data;

function noAutoLink(s) {
  let out = '';
  let prev = false;
  for (const ch of String(s)) {
    const isDigit = ch >= '0' && ch <= '9';
    if (isDigit && prev) out += '\u034F';
    out += ch;
    prev = isDigit;
  }
  return out;
}

const MESES = ['jan','fev','mar','abr','mai','jun','jul','ago','set','out','nov','dez'];

const valorRaw = parseFloat(inv.totalValue || 0)
  .toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });

let dataRaw = 'N/D';
if (inv.issueDate) {
  const d = new Date(inv.issueDate);
  dataRaw = `${String(d.getUTCDate()).padStart(2,'0')} ${MESES[d.getUTCMonth()]} ${d.getUTCFullYear()}`;
}

const nomeEmitente = inv.senderName.length > 40
  ? inv.senderName.substring(0, 40) + '...'
  : inv.senderName;

const numero = noAutoLink(inv.number);
const valor  = noAutoLink(valorRaw);
const data   = noAutoLink(dataRaw);

const caption = `📄 *NF-e Recebida*\n\nNF • ${numero}\nEmitente: ${nomeEmitente}\nValor • ${valor}\nData • ${data}\n\n🔗 https://app.qlmed.com.br/fiscal/invoices`;

const fileName = `DANFE_${inv.number}_${nomeEmitente.replace(/[^a-zA-Z0-9]/g, '_').substring(0, 20)}.pdf`;

// Fetch active users with phone
const apiUrl = $env.QLMED_API_URL;
const apiKey = $env.QLMED_API_KEY;
const usersResp = await this.helpers.httpRequest({
  method: 'GET',
  url: `${apiUrl}/api/users`,
  headers: { 'x-api-key': apiKey },
  json: true,
});

const users = Array.isArray(usersResp)
  ? usersResp
  : (usersResp.users || usersResp.data || []);

function normalizePhone(raw) {
  if (!raw) return null;
  let p = String(raw).replace(/\D/g, '');
  if (!p) return null;
  if (p.startsWith('55')) p = p.substring(2);
  if (p.length < 10 || p.length > 11) return null;
  return '55' + p;
}

const seen = new Set();
const recipients = [];
for (const u of users) {
  if (u.status !== 'active') continue;
  const phone = normalizePhone(u.phone);
  if (!phone) continue;
  if (seen.has(phone)) continue;
  seen.add(phone);
  recipients.push(phone);
}

if (recipients.length === 0) {
  return [];
}

return recipients.map(phone => ({
  json: {
    number: phone,
    mediatype: 'document',
    media: base64,
    mimetype: 'application/pdf',
    fileName: fileName,
    caption: caption,
  }
}));

const inv = $('Filtrar Novas NF-e').item.json;
const item = $input.first();

const pdfBinary = item.binary && item.binary.data ? item.binary.data : null;
const xmlBinary = item.binary && item.binary.xml ? item.binary.xml : null;
if (!pdfBinary || !xmlBinary) {
  throw new Error(`Binaries missing (pdf=${!!pdfBinary}, xml=${!!xmlBinary})`);
}

// Parse duplicatas (vencimentos) from XML
const xmlString = Buffer.from(xmlBinary.data, 'base64').toString('utf-8');
const dupRegex = /<dup>\s*<nDup>([^<]*)<\/nDup>\s*<dVenc>([^<]*)<\/dVenc>\s*<vDup>([^<]*)<\/vDup>\s*<\/dup>/g;
const duplicatas = [];
let m;
while ((m = dupRegex.exec(xmlString)) !== null) {
  duplicatas.push({ numero: m[1], vencimento: m[2], valor: parseFloat(m[3]) });
}

const MESES = ['jan','fev','mar','abr','mai','jun','jul','ago','set','out','nov','dez'];

const valorRaw = parseFloat(inv.totalValue || 0)
  .toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });

let dataRaw = 'N/D';
if (inv.issueDate) {
  const d = new Date(inv.issueDate);
  dataRaw = `${String(d.getUTCDate()).padStart(2,'0')} ${MESES[d.getUTCMonth()]} ${d.getUTCFullYear()}`;
}

const nomeEmitente = inv.senderName || 'Não identificado';
const numeroNf = inv.number;

function formatDate(ds) {
  if (!ds) return 'N/D';
  const [y, mo, dy] = ds.split('-');
  return `${dy}/${mo}/${y}`;
}

function formatBrl(v) {
  return parseFloat(v || 0).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
}

// Tabela de vencimentos (só para financeiro e joseroberto)
let vencimentosHtml = '';
if (duplicatas.length > 0) {
  const rows = duplicatas.map(d =>
    `<tr><td style="padding:4px 10px;border:1px solid #ddd;text-align:center">${d.numero}</td>` +
    `<td style="padding:4px 10px;border:1px solid #ddd;text-align:center">${formatDate(d.vencimento)}</td>` +
    `<td style="padding:4px 10px;border:1px solid #ddd;text-align:right">${formatBrl(d.valor)}</td></tr>`
  ).join('');
  vencimentosHtml = `
  <h3 style="color:#1a5490;margin:20px 0 8px 0">📅 Vencimentos</h3>
  <table style="border-collapse:collapse;font-size:14px;margin-bottom:15px">
    <tr style="background:#f0f4f8">
      <th style="padding:6px 10px;border:1px solid #ddd">Parcela</th>
      <th style="padding:6px 10px;border:1px solid #ddd">Vencimento</th>
      <th style="padding:6px 10px;border:1px solid #ddd">Valor</th>
    </tr>
    ${rows}
  </table>`;
}

const subject = `NF-e Recebida: Nº ${numeroNf} — ${nomeEmitente.substring(0,60)}`;

function buildHtml(includeVencimentos) {
  return `
<div style="font-family:Arial,sans-serif;font-size:14px;color:#222;max-width:600px">
  <h2 style="color:#1a5490;margin:0 0 10px 0">📄 NF-e Recebida</h2>
  <table style="border-collapse:collapse;margin:15px 0">
    <tr><td style="padding:4px 10px 4px 0;font-weight:bold;vertical-align:top">Número:</td><td>${numeroNf}</td></tr>
    <tr><td style="padding:4px 10px 4px 0;font-weight:bold;vertical-align:top">Emitente:</td><td>${nomeEmitente}</td></tr>
    <tr><td style="padding:4px 10px 4px 0;font-weight:bold;vertical-align:top">CNPJ emit.:</td><td>${inv.senderCnpj || '-'}</td></tr>
    <tr><td style="padding:4px 10px 4px 0;font-weight:bold;vertical-align:top">Valor:</td><td>${valorRaw}</td></tr>
    <tr><td style="padding:4px 10px 4px 0;font-weight:bold;vertical-align:top">Emissão:</td><td>${dataRaw}</td></tr>
    <tr><td style="padding:4px 10px 4px 0;font-weight:bold;vertical-align:top">Chave:</td><td style="font-family:monospace;font-size:12px">${inv.accessKey || '-'}</td></tr>
  </table>
  ${includeVencimentos ? vencimentosHtml : ''}
  <p>Em anexo o DANFE (PDF) e o arquivo XML original.</p>
  <p style="margin-top:20px">
    <a href="https://app.qlmed.com.br/fiscal/invoices" style="background:#1a5490;color:#fff;padding:10px 20px;text-decoration:none;border-radius:4px;display:inline-block">Abrir no sistema</a>
  </p>
  <hr style="margin-top:30px;border:none;border-top:1px solid #eee">
  <p style="color:#888;font-size:12px">Mensagem automática enviada pelo Assistente Virtual QL MED.</p>
</div>`;
}

// Fetch active users with phone (same criteria as WhatsApp) + faturamento
const usersResp = await this.helpers.httpRequest({
  method: 'GET',
  url: `${$env.QLMED_API_URL}/api/users`,
  headers: { 'x-api-key': $env.QLMED_API_KEY },
  json: true,
});
const users = Array.isArray(usersResp) ? usersResp : (usersResp.users || usersResp.data || []);

const emails = new Set();
for (const u of users) {
  if (u.status !== 'active') continue;
  if (!u.phone) continue;
  if (!u.email) continue;
  emails.add(String(u.email).trim().toLowerCase());
}
emails.add('faturamento@qlmed.com.br');

if (emails.size === 0) return [];

// Destinatários que recebem vencimentos
const VENCIMENTOS_RECIPIENTS = new Set([
  'financeiro@qlmed.com.br',
  'joseroberto@qlmed.com.br',
]);

const pdfFileName = `DANFE_${numeroNf}.pdf`;
const xmlFileName = `NFE_${inv.accessKey || numeroNf}.xml`;

return Array.from(emails).map(email => ({
  json: {
    to: email,
    subject,
    html: buildHtml(VENCIMENTOS_RECIPIENTS.has(email)),
    invoiceNumber: numeroNf,
    invoiceSender: nomeEmitente,
  },
  binary: {
    pdf: { ...pdfBinary, fileName: pdfFileName, mimeType: 'application/pdf' },
    xml: { ...xmlBinary, fileName: xmlFileName, mimeType: 'application/xml' },
  },
}));
